() => {
  // Enable dark mode via Starlight's theme toggle
  document.documentElement.dataset.theme = 'dark';
  localStorage.setItem('starlight-theme', 'dark');
  return 'Dark mode enabled';
}

() => {
  // Scroll to bottom to see footer
  window.scrollTo(0, document.body.scrollHeight);
  return 'Scrolled to bottom';
}

() => {
  // Get the very bottom of the page
  const footer = document.querySelector('footer');
  const pagination = document.querySelector('.pagination-links, nav[aria-label="Pagination"]');
  const mobileFooter = document.querySelector('.mobile-menu-footer, [data-mobile-menu-footer]');

  // Get all elements near the bottom
  const allFooterLike = document.querySelectorAll('footer, .pagination-links, nav[aria-label]');

  const results = {};

  if (footer) {
    const styles = window.getComputedStyle(footer);
    results.footer = {
      bg: styles.backgroundColor,
      classes: footer.className,
      html: footer.outerHTML.substring(0, 500)
    };
  }

  // Check pagination
  const paginationEl = document.querySelector('.prev-next-nav, [class*="pagination"]');
  if (paginationEl) {
    const styles = window.getComputedStyle(paginationEl);
    results.pagination = {
      bg: styles.backgroundColor,
      classes: paginationEl.className
    };
  }

  // Check the bottom nav/footer area
  const bottomElements = document.querySelectorAll('footer *, .bottom-nav, [class*="footer"]');
  results.bottomCount = bottomElements.length;

  // Get the mobile menu footer if it exists
  const mobileMenuFooter = document.querySelector('[class*="MobileMenuFooter"], [class*="mobile"]');
  if (mobileMenuFooter) {
    const styles = window.getComputedStyle(mobileMenuFooter);
    results.mobileMenuFooter = {
      bg: styles.backgroundColor,
      classes: mobileMenuFooter.className,
      html: mobileMenuFooter.outerHTML.substring(0, 300)
    };
  }

  return results;
}

() => {
  // Scroll to absolute bottom
  window.scrollTo(0, 999999);
  return { scrollY: window.scrollY, docHeight: document.body.scrollHeight, viewportHeight: window.innerHeight };
}

() => {
  window.scrollTo(0, document.body.scrollHeight);
  return { scrollY: window.scrollY, docHeight: document.body.scrollHeight };
}

() => {
  document.documentElement.dataset.theme = 'dark';
  localStorage.setItem('starlight-theme', 'dark');
  window.scrollTo(0, document.body.scrollHeight);
  return 'Dark mode, scrolled to bottom';
}

() => {
  // Get all bottom-area elements and their background colors
  const results = [];

  // Main page background
  const main = document.querySelector('main');
  if (main) {
    results.push({ el: 'main', bg: getComputedStyle(main).backgroundColor });
  }

  // The content area
  const content = document.querySelector('.main-pane, .content-panel, [class*="main"]');
  if (content) {
    results.push({ el: 'content-area', bg: getComputedStyle(content).backgroundColor, cls: content.className });
  }

  // Footer
  const footer = document.querySelector('footer');
  if (footer) {
    results.push({ el: 'footer', bg: getComputedStyle(footer).backgroundColor });
    // Check footer parent
    const parent = footer.parentElement;
    if (parent) {
      results.push({ el: 'footer-parent', bg: getComputedStyle(parent).backgroundColor, tag: parent.tagName, cls: parent.className.substring(0, 100) });
    }
  }

  // Pagination links
  const pagination = document.querySelector('.pagination-links');
  if (pagination) {
    results.push({ el: 'pagination', bg: getComputedStyle(pagination).backgroundColor });
    // Check the pagination link items
    const links = pagination.querySelectorAll('a');
    links.forEach((a, i) => {
      results.push({ el: `pagination-link-${i}`, bg: getComputedStyle(a).backgroundColor, border: getComputedStyle(a).borderColor });
    });
  }

  // The wrapper around the bottom section
  const bottomBar = document.querySelector('.bottom, [class*="bottom"]');
  if (bottomBar) {
    results.push({ el: 'bottom-bar', bg: getComputedStyle(bottomBar).backgroundColor, cls: bottomBar.className });
  }

  // Social links footer / mobile menu footer
  const socialFooter = document.querySelector('[class*="social"], .site-footer, [class*="MobileMenuFooter"]');
  if (socialFooter) {
    results.push({ el: 'social-footer', bg: getComputedStyle(socialFooter).backgroundColor, cls: socialFooter.className.substring(0, 100) });
  }

  // Body and html backgrounds
  results.push({ el: 'body', bg: getComputedStyle(document.body).backgroundColor });
  results.push({ el: 'html', bg: getComputedStyle(document.documentElement).backgroundColor });

  // Check the very last visible element
  const allElements = document.querySelectorAll('body > *');
  const lastEl = allElements[allElements.length - 1];
  if (lastEl) {
    results.push({ el: 'body-last-child', bg: getComputedStyle(lastEl).backgroundColor, tag: lastEl.tagName, cls: lastEl.className.substring(0, 100) });
  }

  // Find the mobile menu footer component
  const mobileFooterSlot = document.querySelector('[class*="mobile-menu"], [data-pagefind-ignore] + *');

  // The wrapping div around everything below main content
  const starlightWrapper = document.querySelector('.sl-container, [class*="starlight"]');
  if (starlightWrapper) {
    results.push({ el: 'sl-container', bg: getComputedStyle(starlightWrapper).backgroundColor, cls: starlightWrapper.className.substring(0, 100) });
  }

  return results;
}

