  1→/**
  2→ * SKF (Skill Forge) Documentation Build Pipeline
  3→ *
  4→ * Generates LLM-friendly files, creates downloadable bundles,
  5→ * and builds the Astro+Starlight site.
  6→ *
  7→ * Build outputs:
  8→ *   build/artifacts/     - With llms.txt, llms-full.txt, ZIPs
  9→ *   build/site/          - Final Astro output (deployable)
 10→ */
 11→
 12→const { execSync } = require('node:child_process');
 13→const fs = require('node:fs');
 14→const path = require('node:path');
 15→const archiver = require('archiver');
 16→
 17→// =============================================================================
 18→// Configuration
 19→// =============================================================================
 20→
 21→const PROJECT_ROOT = path.dirname(__dirname);
 22→const BUILD_DIR = path.join(PROJECT_ROOT, 'build');
 23→
 24→const SITE_URL = process.env.SITE_URL || 'https://armelhbobdad.github.io/bmad-module-skill-forge';
 25→const REPO_URL = 'https://github.com/armelhbobdad/bmad-module-skill-forge';
 26→
 27→// llms-full.txt is consumed by AI agents as context. Most LLMs have ~200k token limits.
 28→// 600k chars ≈ 150k tokens (safe margin).
 29→const LLM_MAX_CHARS = 600_000;
 30→const LLM_WARN_CHARS = 500_000;
 31→
 32→const LLM_EXCLUDE_PATTERNS = ['changelog', 'downloads/'];
 33→
 34→// =============================================================================
 35→// Main Entry Point
 36→// =============================================================================
 37→
 38→async function main() {
 39→  console.log();
 40→  printBanner('SKF Documentation Build Pipeline');
 41→  console.log();
 42→  console.log(`Project root: ${PROJECT_ROOT}`);
 43→  console.log(`Build directory: ${BUILD_DIR}`);
 44→  console.log();
 45→
 46→  // Check for broken internal links before building
 47→  checkDocLinks();
 48→
 49→  cleanBuildDirectory();
 50→
 51→  const docsDir = path.join(PROJECT_ROOT, 'docs');
 52→  const artifactsDir = await generateArtifacts(docsDir);
 53→  const siteDir = buildAstroSite();
 54→
 55→  printBuildSummary(docsDir, artifactsDir, siteDir);
 56→}
 57→
 58→main().catch((error) => {
 59→  console.error(error);
 60→  process.exit(1);
 61→});
 62→
 63→// =============================================================================
 64→// Pipeline Stages
 65→// =============================================================================
 66→
 67→async function generateArtifacts(docsDir) {
 68→  printHeader('Generating LLM files and download bundles');
 69→
 70→  const outputDir = path.join(BUILD_DIR, 'artifacts');
 71→  fs.mkdirSync(outputDir, { recursive: true });
 72→
 73→  generateLlmsTxt(outputDir);
 74→  generateLlmsFullTxt(docsDir, outputDir);
 75→  await generateDownloadBundles(outputDir);
 76→
 77→  console.log();
 78→  console.log(`  \u001B[32m✓\u001B[0m Artifact generation complete`);
 79→
 80→  return outputDir;
 81→}
 82→
 83→function buildAstroSite() {
 84→  printHeader('Building Astro + Starlight site');
 85→
 86→  const siteDir = path.join(BUILD_DIR, 'site');
 87→  const artifactsDir = path.join(BUILD_DIR, 'artifacts');
 88→
 89→  runAstroBuild();
 90→  copyArtifactsToSite(artifactsDir, siteDir);
 91→
 92→  console.log();
 93→  console.log(`  \u001B[32m✓\u001B[0m Astro build complete`);
 94→
 95→  return siteDir;
 96→}
 97→
 98→// =============================================================================
 99→// LLM File Generation
100→// =============================================================================
101→
102→function generateLlmsTxt(outputDir) {
103→  console.log('  → Generating llms.txt...');
104→
105→  const content = [
106→    '# Skill Forge (SKF) Documentation',
107→    '',
108→    '> AST-verified, provenance-backed agent skills compiler with progressive capability tiers.',
109→    '',
110→    `Documentation: ${SITE_URL}`,
111→    `Repository: ${REPO_URL}`,
112→    `Full docs: ${SITE_URL}/llms-full.txt`,
113→    '',
114→    '## Quick Start',
115→    '',
116→    `- **[Getting Started](${SITE_URL}/getting-started/)** - Installation and first steps`,
117→    '',
118→    '## Core Workflows',
119→    '',
120→    `- **[Setup Forge (SF)](${SITE_URL}/workflows/#setup-forge-sf)** - Initialize forge environment`,
121→    `- **[Brief Skill (BS)](${SITE_URL}/workflows/#brief-skill-bs)** - Scope and design a skill`,
122→    `- **[Create Skill (CS)](${SITE_URL}/workflows/#create-skill-cs)** - Compile a skill from brief`,
123→    `- **[Quick Skill (QS)](${SITE_URL}/workflows/#quick-skill-qs)** - Fast skill, no brief needed`,
124→    `- **[Stack Skill (SS)](${SITE_URL}/workflows/#stack-skill-ss)** - Consolidated project stack skill`,
125→    `- **[Update Skill (US)](${SITE_URL}/workflows/#update-skill-us)** - Regenerate after changes`,
126→    `- **[Audit Skill (AS)](${SITE_URL}/workflows/#audit-skill-as)** - Drift detection`,
127→    `- **[Test Skill (TS)](${SITE_URL}/workflows/#test-skill-ts)** - Verify completeness`,
128→    `- **[Export Skill (EX)](${SITE_URL}/workflows/#export-skill-ex)** - Package for distribution`,
129→    `- **[Analyze Source (AN)](${SITE_URL}/workflows/#analyze-source-an)** - Discover what to skill`,
130→    '',
131→    '---',
132→    '',
133→    '## Quick Links',
134→    '',
135→    `- [Full Documentation (llms-full.txt)](${SITE_URL}/llms-full.txt) - Complete docs for AI context`,
136→    `- [Source Bundle](${SITE_URL}/downloads/skf-sources.zip) - Complete source code`,
137→    `- [Prompts Bundle](${SITE_URL}/downloads/skf-prompts.zip) - Agent prompts and workflows`,
138→    '',
139→  ].join('\n');
140→
141→  const outputPath = path.join(outputDir, 'llms.txt');
142→  fs.writeFileSync(outputPath, content, 'utf-8');
143→  console.log(`    Generated llms.txt (${content.length.toLocaleString()} chars)`);
144→}
145→
146→function generateLlmsFullTxt(docsDir, outputDir) {
147→  console.log('  → Generating llms-full.txt...');
148→
149→  const date = new Date().toISOString().split('T')[0];
150→  const files = getAllMarkdownFiles(docsDir);
151→
152→  const output = [
153→    '# Skill Forge (SKF) Documentation (Full)',
154→    '',
155→    '> Complete documentation for AI consumption',
156→    `> Generated: ${date}`,
157→    `> Repository: ${REPO_URL}`,
158→    '',
159→  ];
160→
161→  let fileCount = 0;
162→  let skippedCount = 0;
163→
164→  for (const mdPath of files) {
165→    if (shouldExcludeFromLlm(mdPath)) {
166→      skippedCount++;
167→      continue;
168→    }
169→
170→    const fullPath = path.join(docsDir, mdPath);
171→    try {
172→      const content = readMarkdownContent(fullPath);
173→      output.push(`<document path="${mdPath}">`, content, '</document>', '');
174→      fileCount++;
175→    } catch (error) {
176→      console.error(`    Warning: Could not read ${mdPath}: ${error.message}`);
177→    }
178→  }
179→
180→  const result = output.join('\n');
181→  validateLlmSize(result);
182→
183→  const outputPath = path.join(outputDir, 'llms-full.txt');
184→  fs.writeFileSync(outputPath, result, 'utf-8');
185→
186→  const tokenEstimate = Math.floor(result.length / 4).toLocaleString();
187→  console.log(
188→    `    Processed ${fileCount} files (skipped ${skippedCount}), ${result.length.toLocaleString()} chars (~${tokenEstimate} tokens)`,
189→  );
190→}
191→
192→function getAllMarkdownFiles(dir, baseDir = dir) {
193→  const files = [];
194→
195→  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
196→    const fullPath = path.join(dir, entry.name);
197→
198→    if (entry.isDirectory()) {
199→      files.push(...getAllMarkdownFiles(fullPath, baseDir));
200→    } else if (entry.name.endsWith('.md')) {
201→      const relativePath = path.relative(baseDir, fullPath);
202→      files.push(relativePath);
203→    }
204→  }
205→
206→  return files;
207→}
208→
209→function shouldExcludeFromLlm(filePath) {
210→  const pathParts = filePath.split(path.sep);
211→  if (pathParts.some((part) => part.startsWith('_'))) return true;
212→
213→  return LLM_EXCLUDE_PATTERNS.some((pattern) => filePath.includes(pattern));
214→}
215→
216→function readMarkdownContent(filePath) {
217→  let content = fs.readFileSync(filePath, 'utf-8');
218→
219→  if (content.startsWith('---')) {
220→    const end = content.indexOf('---', 3);
221→    if (end !== -1) {
222→      content = content.slice(end + 3).trim();
223→    }
224→  }
225→
226→  return content;
227→}
228→
229→function validateLlmSize(content) {
230→  const charCount = content.length;
231→
232→  if (charCount > LLM_MAX_CHARS) {
233→    console.error(`    ERROR: Exceeds ${LLM_MAX_CHARS.toLocaleString()} char limit`);
234→    process.exit(1);
235→  } else if (charCount > LLM_WARN_CHARS) {
236→    console.warn(`    \u001B[33mWARNING: Approaching ${LLM_WARN_CHARS.toLocaleString()} char limit\u001B[0m`);
237→  }
238→}
