240→// =============================================================================
241→// Download Bundle Generation
242→// =============================================================================
243→
244→async function generateDownloadBundles(outputDir) {
245→  console.log('  → Generating download bundles...');
246→
247→  const downloadsDir = path.join(outputDir, 'downloads');
248→  fs.mkdirSync(downloadsDir, { recursive: true });
249→
250→  await generateSourcesBundle(downloadsDir);
251→  await generatePromptsBundle(downloadsDir);
