269→  const zipPath = path.join(downloadsDir, 'skf-prompts.zip');
270→  await createZipArchive(srcDir, zipPath, ['docs', '.DS_Store', '__pycache__', 'node_modules']);
271→
272→  const size = Math.floor(fs.statSync(zipPath).size / 1024);
273→  console.log(`    skf-prompts.zip (${size}K)`);
274→}
