307→function printBuildSummary(docsDir, artifactsDir, siteDir) {
308→  console.log();
309→  printBanner('Build Complete!');
310→  console.log();
311→  console.log('Build artifacts:');
312→  console.log(`  Source docs:     ${docsDir}`);
313→  console.log(`  Generated files: ${artifactsDir}`);
314→  console.log(`  Final site:      ${siteDir}`);
315→  console.log();
316→  console.log(`Deployable output: ${siteDir}/`);
317→  console.log();
