321→
322→function listDirectoryContents(dir) {
323→  const entries = fs.readdirSync(dir).slice(0, 15);
324→
325→  for (const entry of entries) {
326→    const fullPath = path.join(dir, entry);
327→    const stat = fs.statSync(fullPath);
328→
329→    if (stat.isFile()) {
330→      const sizeStr = formatFileSize(stat.size);
331→      console.log(`  ${entry.padEnd(40)} ${sizeStr.padStart(8)}`);
332→    } else {
333→      console.log(`  ${entry}/`);
334→    }
335→  }
336→}
337→
338→function formatFileSize(bytes) {
339→  if (bytes > 1024 * 1024) {
340→    return `${(bytes / 1024 / 1024).toFixed(1)}M`;
341→  } else if (bytes > 1024) {
342→    return `${Math.floor(bytes / 1024)}K`;
343→  }
344→  return `${bytes}B`;
345→}
