358→}
359→
360→function copyDirectory(src, dest, exclude = []) {
361→  if (!fs.existsSync(src)) return false;
362→  fs.mkdirSync(dest, { recursive: true });
363→
364→  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
365→    if (exclude.includes(entry.name)) continue;
366→
367→    const srcPath = path.join(src, entry.name);
368→    const destPath = path.join(dest, entry.name);
369→
370→    if (entry.isDirectory()) {
371→      copyDirectory(srcPath, destPath, exclude);
372→    } else {
373→      fs.copyFileSync(srcPath, destPath);
374→    }
375→  }
376→  return true;
377→}
378→
379→function createZipArchive(sourceDir, outputPath, exclude = []) {
380→  return new Promise((resolve, reject) => {
381→    const output = fs.createWriteStream(outputPath);
382→    const archive = archiver('zip', { zlib: { level: 9 } });
383→
384→    output.on('close', resolve);
385→    archive.on('error', reject);
386→
387→    archive.pipe(output);
388→
389→    const baseName = path.basename(sourceDir);
390→    archive.directory(sourceDir, baseName, (entry) => {
391→      for (const pattern of exclude) {
392→        if (entry.name.includes(pattern)) return false;
393→      }
394→      return entry;
395→    });
396→
397→    archive.finalize();
398→  });
399→}
